async (params, browser) => {
  // Open Tinder recommendations
  await browser.open('https://tinder.com/app/recs')

  // Wait for cards
  await browser.waitForSelector('[class*="recsCardboard"], [class*="gamepad"], main', 15000)

  // Let profile render
  await browser.wait(3000)

  // Extract profile
  const result = await browser.evaluate(`const nameEl = document.querySelector('span[class*="Typs(display-1-strong)"], h1, [itemprop="name"], [class*="name"] span'); const name = nameEl?.textContent?.trim() || ''; let age = ''; const nameParent = nameEl?.closest('div'); if (nameParent) { const ageSpan = nameParent.querySelector('span'); if (ageSpan && ageSpan !== nameEl && ageSpan.textContent?.trim()?.match(/^\d{2}$/)) age = ageSpan.textContent.trim(); } if (!age) { document.querySelectorAll('span').forEach(s => { if (!age && s.textContent?.trim()?.match(/^\d{2}$/)) age = s.textContent.trim(); }); } const bioEl = document.querySelector('div[class*="Px(16px)"][class*="Py(12px)"][class*="Us(t)"], [class*="BreakWord"], [class*="bio"]'); const bio = bioEl?.textContent?.trim()?.slice(0, 500) || ''; const interests = []; document.querySelectorAll('div[class^="Bdrs(100px)"] span, [class*="interest"] span, [class*="passion"] span, [class*="Pill"] span').forEach(el => { const t = el.textContent?.trim(); if (t && !interests.includes(t)) interests.push(t); }); return { name, age, bio, interests, url: window.location.href };`)

  return result
}
